def match(pattern: str, text: str) -> bool:
    expr, pos = parse_alternation(pattern, 0)
    if pos != len(pattern):
        return False
    for end_pos in matches(expr, text, 0):
        if end_pos == len(text):
            return True
    return False

def parse_alternation(s, pos):
    left, pos = parse_concat(s, pos)
    while pos < len(s) and s[pos] == '|':
        pos += 1
        right, pos = parse_concat(s, pos)
        left = ('alt', left, right)
    return left, pos

def parse_concat(s, pos):
    items = []
    while pos < len(s) and s[pos] not in '|)':
        item, pos = parse_quantified(s, pos)
        items.append(item)
    if not items:
        return ('empty',), pos
    if len(items) == 1:
        return items[0], pos
    return ('concat', items), pos

def parse_quantified(s, pos):
    item, pos = parse_atom(s, pos)
    if pos < len(s) and s[pos] in '*+?':
        quant = s[pos]
        pos += 1
        return ('quant', item, quant), pos
    return item, pos

def parse_atom(s, pos):
    if pos >= len(s):
        return None, pos
    if s[pos] == '.':
        return ('any',), pos + 1
    elif s[pos] == '[':
        return parse_char_class(s, pos)
    elif s[pos] == '(':
        pos += 1
        expr, pos = parse_alternation(s, pos)
        if pos < len(s) and s[pos] == ')':
            pos += 1
        return expr, pos
    else:
        return ('lit', s[pos]), pos + 1

def parse_char_class(s, pos):
    pos += 1
    negated = False
    if pos < len(s) and s[pos] == '^':
        negated = True
        pos += 1
    chars = set()
    while pos < len(s) and s[pos] != ']':
        if pos + 2 < len(s) and s[pos + 1] == '-':
            start, end = s[pos], s[pos + 2]
            for c in range(ord(start), ord(end) + 1):
                chars.add(chr(c))
            pos += 3
        else:
            chars.add(s[pos])
            pos += 1
    if pos < len(s):
        pos += 1
    return ('class', chars, negated), pos

def matches(expr, text, pos):
    if expr is None or expr[0] == 'empty':
        yield pos
        return
    typ = expr[0]
    if typ == 'lit':
        if pos < len(text) and text[pos] == expr[1]:
            yield pos + 1
    elif typ == 'any':
        if pos < len(text):
            yield pos + 1
    elif typ == 'class':
        if pos < len(text):
            chars, negated = expr[1], expr[2]
            in_class = text[pos] in chars
            if (in_class and not negated) or (not in_class and negated):
                yield pos + 1
    elif typ == 'concat':
        def concat_match(items, p):
            if not items:
                yield p
            else:
                for next_p in matches(items[0], text, p):
                    yield from concat_match(items[1:], next_p)
        yield from concat_match(expr[1], pos)
    elif typ == 'alt':
        yield from matches(expr[1], text, pos)
        yield from matches(expr[2], text, pos)
    elif typ == 'quant':
        item, quant = expr[1], expr[2]
        if quant == '?':
            yield pos
            yield from matches(item, text, pos)
        elif quant == '*':
            yield pos
            for next_p in matches(item, text, pos):
                yield from matches(expr, text, next_p)
        elif quant == '+':
            for next_p in matches(item, text, pos):
                yield from matches(('quant', item, '*'), text, next_p)
